# Initialize AWS services
s3 = boto3.client('s3')
sns = boto3.client('sns')
logs = boto3.client('logs')

# Set up logging to CloudWatch
log_group_name = 'image-processing-log-group'
log_stream_name = 'image-processing-log-stream'

try:
    logs.create_log_group(logGroupName=log_group_name)
except ClientError as e:
    if e.response['Error']['Code'] == 'ResourceAlreadyExistsFault':
        pass

logs.create_log_stream(logGroupName=log_group_name, logStreamName=log_stream_name)

logger = logging.getLogger()
logger.setLevel(logging.INFO)

# Process user-uploaded images from S3
def lambda_handler(event, context):
    bucket_name = event['Records'][0]['s3']['bucket']['name']
    object_key = event['Records'][0]['s3']['object']['key']

    try:
        # Read image from S3
        response = s3.get_object(Bucket=bucket_name, Key=object_key)
        image_data = response['Body'].read()

        # Process image (e.g., resize, compress, etc.)
        processed_image = process_image(image_data)

        # Write processed image back to S3
        s3.put_object(Body=processed_image, Bucket=bucket_name, Key='processed/' + object_key)

        # Send notification via SNS
        sns.publish(
            TopicArn='YOUR_SNS_TOPIC_ARN',
            Message='Image processing complete: ' + object_key,
            Subject='Image Processing Notification'
        )

        logger.info('Image processed successfully: ' + object_key)
    except Exception as e:
        logger.error('Error processing image: ' + str(e))

